{
  "verses": [
    {
      "n": 2,
      "column": "left",
      "text": "Kas warr ta KUNGA\nwarrenus Darbus isteikt / un\nwiſſu winna teizamu Slawu\niſtahſtiht?\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Swehtigi irr tee / kas to\nTeesu turr/ un darra Taifnibu\nallaschin.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Beeminni mannis ak\nKUNGS! pehz tawu labbu\nPrahtu/ prett taweem Laudim/\npeemeſſe mann ar tawn Pesti-\nschann.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Ka mehs redsam tawo Iſ-\nwehleto Labbuimu/ un preezaja-\nmees ar tawo Lauscho Preeku /\nun leeltjaimees ar tawu eemanto-\njann Teefu.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Mehs effam grehkojufchi\nlihds ar muh+eem Tehweem/\nmehs effam pahrkahpuschi / un\nbesdeewigi biſcht.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Muhsu Tehwi Egiptes-\nSemmê ne likke tawus Brih-\nnimus wehrâ/ tee ne atminne-\njahs tawas leelas Schehlastibas/\nbet bija pahrgalwigi Juhr-Mal-\nlâ/ pee tahs Needru-Inhras.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Tattchu wiꞥſch teem pa-\nlihdſeja fawa Wahrda deht / ka\nwiꞥſch teem fawu Warru paraly-\nditu.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Un wiꞥſch lammaja to\nNeedru-Juhru/ ka ta fafikke/un\nwiꞥſch likke tohs zaur Besdib-\nbixeem statgaht/ ta ka zaur wee-\nnu Tuksnefi.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Un wiꞥſch atpestija tohs\nno Eenaidneeku Rohkas/ un at-\nbbvinaja tohs no Nihdetaja\nnas.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Tee Uhdeni apſlihzinu\nwinnu Prettineekus/ ka ne wee\nno teem atlikke.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Tad tizzeja tee winu\nWahrdeem/ tee dseedaja winnu\nar Teikſchanu.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Bet drihs aiſmirfe t\nwinna Darbus/ tee ne pasta\nweja pehz winna Padohinu.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Bet eekahroja ar lee\nRahribu Tuksneſi/ un fahrdin\nja to STIPRU DEEW\npohsta Weeta.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Tad detwe wiſch tee\npehz winnu Rahribas/ bet winu\ndarrija winnu Dwehfeles leeſa\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Un tee fkanfija Mohi\nLehgeri/ un Aaronn ta KUNG\nSwehtu.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Ta Semme atwehrahe\nnn aprihje Datanu/ un apflah\nAbirama Draudsibu.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Un Ugguns eededsah\nstarp winnu Draudses / ween\nLeetnia fadedsinaja tohs Besdee\nwigns.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Tee padarrija weenu Tet\nfu Orebâ / un paklannijah\npreeffch weenas Bildes.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Un tee pahrwehrtija fatu\nGohdu eekſch kahda Wehrſch\nGihmi/ kas Sahlt ehd.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Winnt atsinirfe to STIP\nRU DEEWU fawu Pestitaju\nkas leetas Leetas bij darrijs E\ngiptes-Semmê.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Brihnumus eekſch tah\nSemmes Rain / breeſmigu\nDarbus pee tahs Needru-Juh\nras.\n"
    }
  ],
